      { title: "Water heater leaking", text: "A leak from the bottom of the tank generally can't be repaired and needs replacement. A leak from the top — often the pressure relief valve or a supply connection — is frequently a simple, affordable fix." },
      { title: "Water not getting hot enough or taking too long to heat", text: "Usually a failing thermostat or a heating element that's no longer reaching full output, though sediment buildup insulating the element can produce the same symptom." },
      { title: "Water heater making noise", text: "Rumbling or popping during heating is a classic sign of sediment buildup at the bottom of the tank, insulating the heating element and forcing it to work harder." },
      { title: "Discolored or rusty water", text: "Frequently a sign of anode rod depletion or sediment buildup, both addressed through flushing and maintenance rather than full replacement if caught in time." },
      { title: "Pilot light won't stay lit", text: "Usually a faulty thermocouple or a draft affecting the pilot assembly, rather than an issue with the gas supply itself." },
      { title: "Electric water heater tripping the breaker", text: "Often points to a failed heating element or element wiring drawing excessive current, rather than an issue with the breaker itself." },
      { title: "Inconsistent hot water temperature", text: "Usually a failing thermostat on tank models, or on tankless units, a flow sensor issue that isn't correctly modulating the burner." }
